head.script:
//==================================================================================================================
// id       : fi_401_01_14p
// 이름     : 사업자정보대사
// 경로     : 재무회계/세무/부가세조정/ 부가세자료관리
// 사용계정 : 내부/자회사
// 파라미터 :
//            IN  :
//            OUT :
//
// 비고     : 
//           1:작성부서,2:부가세관리부서,3:사업자,4:전표종류,5:작성자
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//            
//==================================================================================================================

// 로그인사용자 정보
scwin.vLoginCoCd     =  "";  // 소속 자회사 
scwin.vLoginCoClsCd  =  "";  // 회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd =  "";  // 사용자소속구분코드 
scwin.privAdmin      =  "";  // 어드민권한
scwin.userId         =  "";  // 사용자ID
scwin.vCoCd          =  "";  // 회사코드
scwin.vCoClsCd       =  "";  // 소속회사종류 : 회계_회사구분('CO035' : 0:동부 EXPRESS)

scwin.vAdminYn       =  "";  // 어드민여부
scwin.userEmpNo      =  "";  // 사용자번호

scwin.isSubCompany   = false;  // 자회사여부

scwin.acctDeptCd     =   "";  // 회계부서코드
scwin.acctDeptNm     =   "";  // 회계부서명

scwin.isStarted            = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

// <INPUT type="hidden" name="txtCoClsCd"  id="txtCoClsCd">
scwin.txtCoClsCd         = "";  // 회사구분

scwin.ed_coCd_hidVal                 = "";  // 회사코드
scwin.ed_drawAcctDeptCd_hidVal       = "";  // 작성부서
scwin.ed_vatDeclarAcctDeptCd_hidVal  = "";  // 부가세신고부서
scwin.ed_crn_hidVal                  = "";  // 사업자번호
scwin.ed_slipKndCd_hidVal            = "";  // 전표종류
scwin.ed_drawEmpNo_hidVal            = "";  // 작성자


scwin.onpageload = function() {

    console.log("====== onpageload ==================");

    // 회원정보를 json 데이터로 모두 받음
    let memJson = $c.data.getMemInfo();

    // 로그인 정보 추출
    let coCd    = $c.gus.cfIsNull( $c.data.getMemInfo("coCd") ) ? '' : $c.data.getMemInfo("coCd");
    let coClsCd = $c.gus.cfIsNull( $c.data.getMemInfo("coClsCd") ) ? '' : $c.data.getMemInfo("coClsCd");
    let userHomeClsCd = $c.data.getMemInfo("userHomeClsCd");  // 사용자소속구분코드
    let userId     = $c.data.getMemInfo("userId");
    let privAdmin  = $c.data.getMemInfo("privAdmin");
    let empNo      = $c.data.getMemInfo("empNo");

    scwin.vLoginCoCd     = coCd;
    scwin.vLoginCoClsCd  = coClsCd;
    scwin.vUserHomeClsCd = userHomeClsCd;

    scwin.vCoCd          = coCd;      
    scwin.vCoClsCd       = coClsCd;   
    scwin.userId         = userId;
    scwin.vAdminYn       = privAdmin;
    scwin.userEmpNo      = empNo;

    console.log("▶▶ vLoginCoCd : "+ scwin.vLoginCoCd +"   loginCoClsCd : "+ scwin.vLoginCoClsCd );
    console.log("▶▶ vCoCd      : "+ scwin.vCoCd +"   vCoClsCd : "+ scwin.vCoClsCd );
    console.log("▶▶ userId     : "+ scwin.userId +"   userEmpNo : "+ scwin.userEmpNo);
    console.log("▶▶ vUserHomeClsCd : "+ scwin.vUserHomeClsCd +"   vAdminYn : "+ scwin.vAdminYn);
//    console.log("▶▶ memJson : "+ JSON.stringify(memJson));

    // 회계부서코드/명
    let acctDeptCd = $c.data.getMemInfo("acctDeptCd");
    let acctDeptNm = $c.data.getMemInfo("acctDeptNm");

    scwin.acctDeptCd = acctDeptCd;
    scwin.acctDeptNm = acctDeptNm;

    console.log("▶▶ acctDeptCd : "+ scwin.acctDeptCd +"   acctDeptNm : "+ scwin.acctDeptNm);

    // onPageLoad 에 써야 함 !!!!
    scwin.valueObject    = $c.data.getParameter();

    // 공통코드 : onPageLoad 에 위치
    const codeOptions = [
         { grpCd : "FI019", compID : "lc_pchsSellCls" }  // 매입매출구분
        ,{ grpCd : "FI005", compID : "lc_deductCls"   }  // 공제구분
        ,{ grpCd : "FI004", compID : "lc_zeroTaxCls"  }  // 영세율구분
        ,{ grpCd : "FM052", compID : "gr_evid:debisQuit,gr_evid:taxQuit" }  // 폐업여부
    ];
    console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    console.log("==-==-== onUdcCompleted");

    $p.setTimeout(function() {

  	    scwin.f_Header();    

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 증빙종류 조회 이후
//-------------------------------------------------------------------------
scwin.afterEvidClsCd = function() {
    console.log("=== afterEvidClsCd (증빙종류 조회 이후)");
  	    scwin.f_Setting();

        // KYU_ORDER
        ed_coCd.setValue( scwin.valueObject["coCd"] );
  	    scwin.f_PopUpCompanyInfo('T');

        // KYU_ORDER : 회사팝업 후에 조회
  	    // scwin.f_Retrieve();  
}


// @@ ====== 준비 ============================================================================== //

//-------------------------------------------------------------------------
// 헤더생성
//-------------------------------------------------------------------------
scwin.f_Header = async function() {
    //증빙종류 조회
	// ds_evidClsCd.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
	// 								+ "&queryId=retrieveEvidInfo";
	// ds_evidClsCd.Reset();

	// 1. 증빙종류 조회
    scwin.getEvidInfo();

    console.log("  ----- ----- 증빙종류 submitdone 이후 : f_PchsSellCls 보다 앞에 위치 ----- -----");
};

//-------------------------------------------------------------------------
// 증빙종류 조회
//-------------------------------------------------------------------------
scwin.getEvidInfo = async function() {
	//증빙종류 조회
	// ds_evidClsCd.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
	// 								+ "&queryId=retrieveEvidInfo";
	// ds_evidClsCd.Reset();

    ds_commonCode.setEmptyValue();

	const strParam = {
                  sysCd              : "CommonEBC"           // 시스템코드
                , queryId            : "retrieveEvidInfo"    // 쿼리ID
                , param1             : ""
                , param2             : ""
                , param3             : ""                   // CD
            };

    //데이터셋에 정보설정
    ds_commonCode.setJSON(strParam);
    await $c.sbm.execute(sbm_evidClsCd);
};

//-------------------------------------------------------------------------
// 증빙종류조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_evidClsCd_submitdone = function (e) {
    console.log("▷ sbm_evidClsCd_submitdone (증빙종류조회)");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

    if(e.responseJSON.GAUCE) {
        ds_evidClsCd.setJSON(e.responseJSON.GAUCE);
    }

    scwin.afterEvidClsCd();
};

//-------------------------------------------------------------------------
// 조회조건 셋팅
//-------------------------------------------------------------------------
scwin.f_Setting = function(){
    console.log("=== f_Setting");

    console.log("^^^^^  before fi_401_01_14p (사업자정보대사) valueObject : "+ JSON.stringify(scwin.valueObject));

	// ed_slipDtSt.text = valueObject.slipDtSt ;
    // ed_slipDtEnd.text = valueObject.slipDtEnd  ;

    ed_spplyDtSt.setValue( scwin.valueObject["spplyDtSt"] );
	ed_spplyDtEnd.setValue( scwin.valueObject["spplyDtEnd"] );

    ed_slipNo.setValue( scwin.valueObject["slipNo"] );
    ed_postDtSt.setValue( scwin.valueObject["postDtSt"] );
    ed_postDtEnd.setValue( scwin.valueObject["postDtEnd"] );

    // ed_slipKndCd.text = valueObject.slipKndCd ;
    // txt_slipKndNm.value = valueObject.slipKndNm ;
    // ed_drawAcctDeptCd.text = valueObject.drawAcctDeptCd ;
    // txt_drawAcctDeptNm.value = valueObject.drawAcctDeptNm ;

    ed_slipKndCd.setValue( scwin.valueObject["slipKndCd"] );
    ed_slipKndNm.setValue( scwin.valueObject["slipKndNm"] );
    ed_drawAcctDeptCd.setValue( scwin.valueObject["drawAcctDeptCd"] );
    ed_drawAcctDeptNm.setValue( scwin.valueObject["drawAcctDeptNm"] );

    lc_pchsSellCls.setValue( scwin.valueObject["pchsSellCls"] );

    console.log("  evidClsCd : "+scwin.valueObject["evidClsCd"]);

    lc_evidClsCd.setValue( scwin.valueObject["evidClsCd"] );
    lc_deductCls.setValue( scwin.valueObject["deductCls"] );
    lc_postYn.setValue( scwin.valueObject["postYn"] );
    lc_zeroTaxCls.setValue( scwin.valueObject["zeroTaxCls"] );

    ed_vatDeclarAcctDeptCd.setValue( scwin.valueObject["vatDeclarAcctDeptCd"] );
    ed_vatDeclarAcctDeptNm.setValue( scwin.valueObject["vatDeclarAcctDeptNm"] );
    ed_crn.setValue( scwin.valueObject["crn"] );
    ed_crnNm.setValue( scwin.valueObject["crnNm"] );

    // 삭제여부
    console.log("  valueObject[delYn] : "+ scwin.valueObject["delYn"]);
    lc_delYn.setValue( scwin.valueObject["delYn"] );
    ed_drawEmpNo.setValue( scwin.valueObject["drawEmpNo"] );

	ed_spplyDtSt.focus();
};


// @@ ====== 준비 - 이벤트 ===================================================================== //

//-------------------------------------------------------------------------
// 매입,매출변경시
//-------------------------------------------------------------------------
scwin.f_PchsSellCls = function(){
    console.log("=== f_PchsSellCls(매입,매출 변경시)");

    if(lc_pchsSellCls.getValue()=="1"){
        console.log("  ------------- 1: 매출 -  비활성 (공제구분)");

    	lc_deductCls.setSelectedIndex(0);  // 전체

// debugger;
    	$c.gus.cfDisableObjects([lc_deductCls]);
// debugger;
    }else{
    	$c.gus.cfEnableObjects([lc_deductCls]);
        console.log("  ------------- 매출 아님 - 활성 (공제구분)");
    }

    // 증빙구분변경시
    scwin.f_EvidClsCd();
};

//-------------------------------------------------------------------------
// 회계처리변경시
//-------------------------------------------------------------------------
scwin.f_PostYn = function(){
    console.log("=== f_PostYn (회계처리변경시)");

	if(lc_postYn.getValue() =="0"){  // 가결
		ed_postDtSt.setValue("");
		ed_postDtEnd.setValue("");
        // 회계일자 비활성
		$c.gus.cfDisableObjects([ed_postDtSt]);
		$c.gus.cfDisableObjects([ed_postDtEnd]);
        console.log("  ==--==- 비활성 (회계일자)");
	}else{
        // 회계일자 활성
		$c.gus.cfEnableObjects([ed_postDtSt]);
		$c.gus.cfEnableObjects([ed_postDtEnd]);
        console.log("  ==--== 활성 (회계일자)");
	}
};

//-------------------------------------------------------------------------
// 증빙구분변경시
//-------------------------------------------------------------------------
scwin.f_EvidClsCd = function(){
    console.log("=== f_EvidClsCd (증빙구분변경시)");

    // 20 : 영세율세금계산서
	if(lc_evidClsCd.getValue() == "20") {
		$c.gus.cfEnableObjects([lc_zeroTaxCls]);  // 영세율구분 활성
        console.log("  ==--== 활성 (영세율구분)");
	}else{
		lc_zeroTaxCls.setSelectedIndex(0);  // 전체
		$c.gus.cfDisableObjects([lc_zeroTaxCls]);  // 영세율구분 비활성
        console.log("  ==--== 비활성 (영세율구분)");
	}
};



// @@ ====== 조회 ============================================================================== //

//-------------------------------------------------------------------------
// 재조회
//-------------------------------------------------------------------------
scwin.f_SearchClear = function (e) {
    // cfInitObjects(searchTable);
	$c.gus.cfInitObjects(searchTable);

    // KYU_NEW
    $c.gus.cfInitObjects([ed_coCd,ed_coNm]);             // 회사코드
    $c.gus.cfInitObjects([ed_spplyDtSt,ed_spplyDtEnd]);  // 계산서일자
    lc_pchsSellCls.setValue("1");  // 매출
    lc_evidClsCd.setValue("10");   // 세금계산서
    lc_postYn.setValue("-1");      // 전체
    lc_delYn.setValue("-1");       // 전체

    scwin.ed_coCd_hidVal                 = "";  // 회사코드
    scwin.ed_drawAcctDeptCd_hidVal       = "";  // 작성부서
    scwin.ed_vatDeclarAcctDeptCd_hidVal  = "";  // 부가세신고부서
    scwin.ed_crn_hidVal                  = "";  // 사업자번호
    scwin.ed_slipKndCd_hidVal            = "";  // 전표종류
    scwin.ed_drawEmpNo_hidVal            = "";  // 작성자
};

//-------------------------------------------------------------------------
// 조회(사업자정보대사)
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    console.log("====== f_Retrieve ==================");

	// if (!cfValidate([ed_coCd,ed_spplyDtSt,ed_spplyDtEnd,ed_slipDtSt,ed_slipDtEnd,ed_postDtSt,ed_postDtEnd,ed_slipNo]))

    // KYU_TEST : 2026-02-06 작성일자, 회계일자 점검 제외
    // let rtn1 = await $c.gus.cfValidate([ed_coCd,ed_spplyDtSt,ed_spplyDtEnd,ed_slipDtSt,ed_slipDtEnd,ed_postDtSt,ed_postDtEnd,ed_slipNo]);
    let rtn1 = await $c.gus.cfValidate([ed_coCd,ed_spplyDtSt,ed_spplyDtEnd,ed_slipNo]);
    if ( !rtn1 )
		return false;

	if (!$c.gus.cfIsAfterDate(ed_spplyDtSt.getValue().trim(), ed_spplyDtEnd.getValue().trim())){
    	await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
    	ed_spplyDtSt.focus();
    	return false;
    }

	if (!$c.gus.cfIsAfterDate(ed_slipDtSt.getValue().trim(), ed_slipDtEnd.getValue().trim())){
    	await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
    	ed_slipDtSt.focus();
    	return false;
    }

    if (!$c.gus.cfIsAfterDate(ed_postDtSt.getValue().trim(), ed_postDtEnd.getValue().trim())){
    	await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
    	ed_postDtSt.focus();
    	return false;
    }

    // ds_search.UseChangeInfo = false;
	// tr_search.Action="/ac.fi.taxbiz.vatctrl.RetrieveCrnComparisonCMD.do";
	// tr_search.post();

    ds_search.set("coClsCd", scwin.txtCoClsCd);

    var dcJSON = ds_search.getJSON();
    console.log("  *** ds_search : "+ JSON.stringify(dcJSON));

    $c.sbm.execute(sbm_search);
};


//-------------------------------------------------------------------------
// 조회(사업자정보대사) submitdone
//-------------------------------------------------------------------------
scwin.sbm_search_submitdone = async function (e) {
    console.log("▷ sbm_search_submitdone");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) {
// <!-- 증빙조회 DataSet -->
// language=JavaScript for=tr_search event=OnFail()>
//     cfShowError(tr_search);
        $c.gus.cfEnableKeyData();
        return;
    }

// language=JavaScript for=ds_evid event=OnLoadCompleted(rowCnt)>
//   cfHideDSWaitMsg(gr_evid);
//   cfShowTotalRows(totalRows, rowCnt);
    var rowCnt = ds_evid.getTotalRow();
    ed_totalRows.setValue(rowCnt);
    if( rowCnt == 0 ){
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	}
};


// @@ ====== 그리드 / DS ======================================================================= //

//-------------------------------------------------------------------------
// ds_evid_ondataload 정렬 / 셀 백그라운드 처리
//-------------------------------------------------------------------------
scwin.ds_evid_ondataload = function () {
// <!-- 부가세목록 DataSet -->
// <object id="ds_evid" classid="<%=DGauceCLSID.DATASET%>">
// 	 <param name=SortExpr          value="+pchsEvidNo">

    ds_evid.sort("pchsEvidNo", 0);     // 0:오름차순 , 1:내림차순

    // 삭제일 때 #CCCCCC (회색) 지정 : 증빙번호 ~ 수정일자 까지만
    for ( i=0; i < ds_evid.getTotalRow(); i++ ) {
        if ( ds_evid.getCellData(i, "delYn") == "1")  {
            gr_evid.setCellBackgroundColor(i, "gbn", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "supplierCrn", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "supplierCrnNm", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "debisQuit", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "debisTaxnNm", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "spplyDt", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "taxQuit", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "taxTaxnNm", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "taxQuitDt", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "spplyAmt", "#CCCCCC");
            gr_evid.setCellBackgroundColor(i, "vat", "#CCCCCC");
        }
    }  // end of for
};


//-------------------------------------------------------------------------
// 전표내역팝업 로딩
//-------------------------------------------------------------------------
scwin.gr_evid_oncellclick = function (rowIndex, columnIndex, columnId) {
    var Row = rowIndex;
    var Colid = columnId;
// <!-- 전표번호,증빙구분클릭시  -->
// language="javascript"  for=gr_evid event=OnClick(Row,Colid)>
		if(Colid=="slipNo" && Row >= 0){
			$c.gus.cfShowSlipInfo(ds_evid.getCellData(Row,"slipNo"));
		}
};


// @@ ====== 팝업 ============================================================================== //

//-------------------------------------------------------------------------
// 회사코드 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function(pWinCloseTF )  {
    console.log("=== f_PopUpCompanyInfo ( pWinCloseTF[ "+pWinCloseTF+" ]");

    // var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
	// 							,ed_coCd.text, txt_coNm.value
	// 							,pWinCloseTF,null,null,null,null
	// 							,null,null,null,null,null);
    // KYU_TEST : 회사코드 코드 null일 때 팝업 안뜨게 처리 : 2026-01-19
    let pNoDataCloseTF = pWinCloseTF;
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc
                                ,ed_coCd.getValue(), ed_coNm.getValue()
                                ,pWinCloseTF,null,null,null,null
                                ,null,null,null,null,null,null,null,null,pNoDataCloseTF );
};

//-------------------------------------------------------------------------
// 전표종류 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_slipKndCd_onclickEvent = function (e) {
    scwin.f_openPopUp('4','F');
};

//-------------------------------------------------------------------------
// 작성부서 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_drawAcctDeptCd_onclickEvent = function (e) {
    scwin.f_openPopUp('1','F');
};

//-------------------------------------------------------------------------
// 부가세관리부서 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_vatDeclarAcctDeptCd_onclickEvent = function (e) {
    scwin.f_openPopUp('2','F');
};

//-------------------------------------------------------------------------
// 사업자번호 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_crn_onclickEvent = function (e) {
    scwin.f_openPopUp('3','F');
};

//-------------------------------------------------------------------------
// 작성자 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_drawEmpNo_onclickEvent = function (e) {
    scwin.f_openPopUp('5','T');
};


//-------------------------------------------------------------------------
// 팝업 @@
//     1:작성부서,2:부가세관리부서,3:사업자,4:전표종류,5:작성자
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function(flag,check) {
    console.log("=== f_openPopUp ( flag[ "+flag+" ]  check[ "+check+" ]   1:작성부서,2:부가세관리부서,3:사업자,4:전표종류,5:작성자)");
	// var rtnList = new Array();
    switch (flag)
    {
        case '1':
        	// 작성부서
			var param = ",,,,"+ed_coCd.getValue()+","+scwin.txtCoClsCd;
            console.log("  작성부서 popup  param ["+ param +"]");

            // rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo2',ed_drawAcctDeptCd.text.trim(),txt_drawAcctDeptNm.value,check,null,null,null,null,param,null,null,null,null);
			udc_drawAcctDeptCd.cfCommonPopUp(scwin.udc_drawAcctDeptCd_callBackFunc,ed_drawAcctDeptCd.getValue().trim(),ed_drawAcctDeptNm.getValue(),check,null,null,null,null,param,null,null,null,null);
			// scwin.f_resultPopEd(ed_drawAcctDeptCd,ed_drawAcctDeptNm,rtnList);

        	break;

        case '2':
			// 부가세신고부서조회(2016.12.30)  기존 : 부가세관리부서조회
			var param = ",,0,"+ed_coCd.getValue()+","+scwin.txtCoClsCd+","+ed_spplyDtSt.getValue().substring(0,4);
            console.log("  부가세신고부서 popup  param ["+ param +"]");

            // rtnList = cfCommonPopUp('retrieveVatDeclarAcctDeptCd',ed_vatDeclarAcctDeptCd.text.trim(),txt_vatDeclarAcctDeptNm.value,check,null,null,null,null,param,null,null,null,null);
            udc_vatDeclarAcctDeptCd.cfCommonPopUp(scwin.udc_vatDeclarAcctDeptCd_callBackFunc,ed_vatDeclarAcctDeptCd.getValue().trim(),ed_vatDeclarAcctDeptNm.getValue(),check,null,null,null,null,param,null,null,null,null);

        	break;

        case '3':
			// 사업자번호
			var param ="";
			var selectID ='retrieveCrnInfo';

			if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU ) {
				param 	 = ","+ ed_coCd.getValue();
				selectID = 'retrieveCrnClntInfo';
			}

            console.log("  사업자번호 popup  param ["+ param +"]  selectId ["+selectID+"]");

            udc_crn.setSelectId(selectID);

            // rtnList = cfCommonPopUp(selectID,ed_crn.text.trim(),txt_crnNm.value,check,null,null,null,null,param,null,null,null,null);
            udc_crn.cfCommonPopUp(scwin.udc_crn_callBackFunc,ed_crn.getValue().trim(),ed_crnNm.getValue(),check,null,null,null,null,param,null,null,null,null);
			// scwin.f_resultPopEd(ed_crn,ed_crnNm,rtnList);
			break;

        case '4':
			// 전표종류
            // rtnList = cfCommonPopUp('retrieveSlipKndCd',ed_slipKndCd.text.trim(),txt_slipKndNm.value,check,null,null,null,null,"0",null,null,null,null);
            udc_slipKndCd.cfCommonPopUp( scwin.udc_slipKndCd_callBackFunc,ed_slipKndCd.getValue().trim(),ed_slipKndNm.getValue(),check,null,null,null,null,"0",null,null,null,null);
			// scwin.f_resultPopEd(ed_slipKndCd,ed_slipKndNm,rtnList);
            break;

        case '5':
            // 작성자 (사원)
			var param = ed_coCd.getValue() +","+ scwin.txtCoClsCd;
            console.log("  작성자 popup  param ["+ param +"]");

            // rtnList = cfCommonPopUp('retrieveAcEmpInfo',ed_drawEmpNo.text.trim(),ed_drawEmpNm.value,check,null,null,null,null,param,null,null,null,null);
            udc_drawEmpNo.cfCommonPopUp( scwin.udc_drawEmpNo_callBackFunc,ed_drawEmpNo.getValue().trim(),ed_drawEmpNm.getValue(),check,null,null,null,null,param,null,null,null,null);
			// scwin.f_resultPopEd(ed_drawEmpNo,ed_drawEmpNm,rtnList);
            break;

        default:
        	break;
    }
};


// @@ ====== 팝업 callBackFunc ================================================================= //
//   1:작성부서,2:부가세관리부서,3:사업자,4:전표종류,5:작성자

//-------------------------------------------------------------------------
// 회사코드조회 callBackFunc
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function(rtnList) {
    console.log("▲ udc_coCd_callBackFunc (회사코드조회 팝업 callBackFunc)");
    console.log("   rtnList ["+rtnList+"]");

	// SET	 
	if(rtnList != null ) { 
		if (rtnList[0] == "N/A") return; 

		if(scwin.ed_coCd_hidVal != rtnList[0] )  scwin.f_initObj();

		ed_coCd.setValue( rtnList[0] );	// 코드
		ed_coNm.setValue( rtnList[5] ); // 회사명 
		scwin.ed_coCd_hidVal = rtnList[0];  // 히든값
		scwin.txtCoClsCd     = rtnList[1];	// 회사구분    

	}else{
		ed_coCd.setValue( "" );	// 코드
		ed_coNm.setValue( "" ); // 회사명 
		scwin.ed_coCd_hidVal = "";  // 히든값
		scwin.txtCoClsCd     = "";	// 회사구분    
	}

    console.log("  scwin.txtCoClsCd ["+scwin.txtCoClsCd +"]");

	if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU )  {  	// 자회사 회계 시스템 
		scwin.isSubCompany = true;
	}else{
		scwin.isSubCompany = false;
	}

   	    if(scwin.isSubCompany) {// 자회사 회계 시스템
            scwin.txtSlipKndCd = ACConstants.SLIPKNDCD_SUB_COMPANY_EXPENSE; // 전표 종류 : 자회사-경비전표
   	    }else{
   	        scwin.txtSlipKndCd = ACConstants.SLIPKNDCD_EXPENSE; // 전표 종류 :  경비전표
   	    }

    if ( scwin.isStarted == true ) {  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

        // KYU_ORDER
	    if('T' == scwin.vAdminYn  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
		    $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_coCd ]);    
	    }else {
		    $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_coCd  ]);   
	    }
        scwin.isStarted       = false;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

        // KYU_ORDER : 회사팝업 후에 최초 조회
  	    scwin.f_Retrieve(); 
    }
};

