scwin.f_Excel = async function(){
    // var objGridName = eval("gr_evid");
    // if (cfConfirmMsg("Excel로 다운로드 하시겠습니까?")) {
    // 	cfGridToExcel(objGridName, "부가세자료관리_폐업자조회","부가세자료조회_폐업자조회.xls",8+16);
	// }

    if ( ds_evid.getTotalRow() == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
		return false;
    }

    var sheetTitle = "부가세자료관리_폐업자조회";
    let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
        let options = {
            fileName: "부가세자료관리_폐업자조회"+ ".xlsx",
            sheetName: sheetTitle
          , bodyWordwrap     : true   // 줄바꿈
        };

        $c.data.downloadGridViewExcel(gr_evid, options);
    }
};
